CREATE EXTENSION IF NOT EXISTS pgcrypto;
CREATE TABLE IF NOT EXISTS users (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), telegram_id BIGINT NOT NULL UNIQUE, first_name TEXT, last_name TEXT, username TEXT, language_code TEXT NOT NULL DEFAULT 'uz', last_seen_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS runtime_settings (key TEXT PRIMARY KEY, value TEXT NOT NULL, updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS vacancies (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), title TEXT NOT NULL, description TEXT, salary_from INT, salary_to INT, salary_text TEXT, image_url TEXT, is_active BOOLEAN NOT NULL DEFAULT TRUE, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE INDEX IF NOT EXISTS idx_vacancies_active ON vacancies (is_active, created_at DESC);
CREATE TABLE IF NOT EXISTS vacancy_questions (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), vacancy_id UUID NOT NULL REFERENCES vacancies(id) ON DELETE CASCADE, field_key TEXT NOT NULL, question_uz TEXT NOT NULL, question_ru TEXT NOT NULL, input_type TEXT NOT NULL, is_required BOOLEAN NOT NULL DEFAULT TRUE, sort_order INT NOT NULL DEFAULT 0, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), UNIQUE (vacancy_id, field_key));
CREATE TABLE IF NOT EXISTS vacancy_question_options (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), question_id UUID NOT NULL REFERENCES vacancy_questions(id) ON DELETE CASCADE, value TEXT NOT NULL, label_uz TEXT NOT NULL, label_ru TEXT NOT NULL, sort_order INT NOT NULL DEFAULT 0, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS courses (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), title TEXT NOT NULL, description TEXT, price_text TEXT, image_url TEXT, is_active BOOLEAN NOT NULL DEFAULT TRUE, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE INDEX IF NOT EXISTS idx_courses_active ON courses (is_active, created_at DESC);
CREATE TABLE IF NOT EXISTS applications (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), user_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE, telegram_id BIGINT NOT NULL, vacancy_id UUID REFERENCES vacancies(id) ON DELETE SET NULL, status TEXT NOT NULL, current_step TEXT, submitted_at TIMESTAMPTZ, reviewed_at TIMESTAMPTZ, reviewed_by BIGINT, rejection_reason TEXT, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE UNIQUE INDEX IF NOT EXISTS uniq_active_application_per_user ON applications (telegram_id) WHERE status = 'in_progress';
CREATE INDEX IF NOT EXISTS idx_app_status ON applications (status, updated_at DESC);
CREATE TABLE IF NOT EXISTS application_answers (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), application_id UUID NOT NULL REFERENCES applications(id) ON DELETE CASCADE, field_key TEXT NOT NULL, field_value TEXT NOT NULL, field_type TEXT NOT NULL, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), UNIQUE (application_id, field_key));
CREATE TABLE IF NOT EXISTS application_files (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), application_id UUID NOT NULL REFERENCES applications(id) ON DELETE CASCADE, file_role TEXT NOT NULL, telegram_file_id TEXT NOT NULL, cloudinary_url TEXT, cloudinary_public_id TEXT, file_kind TEXT NOT NULL DEFAULT 'telegram', created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), UNIQUE (application_id, file_role));
CREATE TABLE IF NOT EXISTS course_enrollments (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), user_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE, telegram_id BIGINT NOT NULL, course_id UUID NOT NULL REFERENCES courses(id) ON DELETE CASCADE, status TEXT NOT NULL, current_step TEXT, submitted_at TIMESTAMPTZ, reviewed_at TIMESTAMPTZ, reviewed_by BIGINT, rejection_reason TEXT, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE UNIQUE INDEX IF NOT EXISTS uniq_active_enrollment_per_user ON course_enrollments (telegram_id) WHERE status = 'in_progress';
CREATE TABLE IF NOT EXISTS enrollment_answers (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), enrollment_id UUID NOT NULL REFERENCES course_enrollments(id) ON DELETE CASCADE, field_key TEXT NOT NULL, field_value TEXT NOT NULL, field_type TEXT NOT NULL, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), UNIQUE (enrollment_id, field_key));
CREATE TABLE IF NOT EXISTS flow_sessions (telegram_id BIGINT PRIMARY KEY, user_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE, flow_type TEXT NOT NULL, step TEXT NOT NULL, payload JSONB NOT NULL DEFAULT '{}'::jsonb, version INT NOT NULL DEFAULT 1, last_activity_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), expires_at TIMESTAMPTZ NOT NULL, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS processed_updates (update_id BIGINT PRIMARY KEY, telegram_id BIGINT, kind TEXT NOT NULL, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
